          </div>
        </div>
      </header>

      {/* Main Content */}
      <div className="dashboard-content">
        {/* Top Info Bar */}
        <div className="info-bar">
          <div className="info-item">
            <span className="info-label">GLOBAL RANK</span>
            <span className="info-value">#{userStats.rank}</span>
