import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import './Register.css';

const Register = () => {
    const navigate = useNavigate();
    const [formData, setFormData] = useState({
        username: '',
        email: '',
        password: ''
    });
    const [message, setMessage] = useState('');
    const [loading, setLoading] = useState(false);

    const handleChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            const response = await fetch('/api/auth/register', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(formData),
            });

            const data = await response.json();
            if (response.ok) {
                setMessage('✅ Реєстрація успішна! Перенаправлення на логін...');
                setFormData({ username: '', email: '', password: '' });
                setTimeout(() => {
                    navigate('/login');
                }, 1500);
            } else {
                setMessage(`❌ Помилка: ${data.error}`);
            }
        } catch (error) {
            setMessage('❌ Не вдалося з\'єднатися з сервером');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="auth-container">
            <div className="auth-card">
                <div className="logo-box"></div>
                <h1>UPL Fantasy League</h1>
                <p className="subtitle">Build your dream Ukrainian Premier League team</p>

                <h2 className="welcome-title">Create Account</h2>

                <form onSubmit={handleSubmit}>
                    <div className="input-group">
                        <label>Username</label>
                        <input
                            type="text"
                            name="username"
                            placeholder="Nazar"
                            value={formData.username}
                            onChange={handleChange}
                            disabled={loading}
                            required
                        />
                    </div>
                    <div className="input-group">
                        <label>Email</label>
                        <input
                            type="email"
                            name="email"
                            placeholder="your.email@example.com"
                            value={formData.email}
                            onChange={handleChange}
                            disabled={loading}
                            required
                        />
                    </div>
                    <div className="input-group">
                        <label>Password</label>
                        <input
                            type="password"
                            name="password"
                            placeholder="••••••••"
                            value={formData.password}
                            onChange={handleChange}
                            disabled={loading}
                            required
                        />
                    </div>
                    <button type="submit" className="btn-primary" disabled={loading}>
                        {loading ? 'Обробка...' : 'Sign Up'}
                    </button>
                </form>

                {message && <p className="status-message">{message}</p>}

                <p className="footer-text">
                    Already have an account? <a href="#" onClick={(e) => { e.preventDefault(); navigate('/login'); }}>Sign In</a>
                </p>
            </div>
        </div>
    );
};

export default Register;

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import './Register.css';

const Register = () => {
    const navigate = useNavigate();
    const [formData, setFormData] = useState({
        username: '',
        email: '',
        password: ''
    });
    const [message, setMessage] = useState('');
    const [loading, setLoading] = useState(false);

    const handleChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            const response = await fetch('/api/auth/register', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(formData),
            });

            const data = await response.json();
            if (response.ok) {
                setMessage('✅ Реєстрація успішна! Перенаправлення на логін...');
                //  Зберігаємо userId в localStorage
                localStorage.setItem('userId', data.userId);
                localStorage.setItem('email', data.email);
                localStorage.setItem('fullName', data.fullName);
                setFormData({ username: '', email: '', password: '' });
                setTimeout(() => {
                    navigate('/dashboard');
                }, 1500);
            } else {
                setMessage(`❌ Помилка: ${data.error}`);
            }
        } catch (error) {
            setMessage('❌ Не вдалося з\'єднатися з сервером');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="auth-container">
            <div className="auth-card">
                <div className="logo-box"></div>
                <h1>UPL Fantasy League</h1>
                <p className="subtitle">Build your dream Ukrainian Premier League team</p>

                <h2 className="welcome-title">Create Account</h2>

                <form onSubmit={handleSubmit}>
                    <div className="input-group">
                        <label>Username</label>
                        <input
                            type="text"
                            name="username"
                            placeholder="Nazar"
                            value={formData.username}
                            onChange={handleChange}
                            disabled={loading}
                            required
                        />
                    </div>
                    <div className="input-group">
                        <label>Email</label>
                        <input
                            type="email"
                            name="email"
                            placeholder="your.email@example.com"
                            value={formData.email}
                            onChange={handleChange}
                            disabled={loading}
                            required
                        />
                    </div>
                    <div className="input-group">
                        <label>Password</label>
                        <input
                            type="password"
                            name="password"
                            placeholder="••••••••"
                            value={formData.password}
                            onChange={handleChange}
                            disabled={loading}
                            required
                        />
                    </div>
                    <button type="submit" className="btn-primary" disabled={loading}>
                        {loading ? 'Обробка...' : 'Sign Up'}
                    </button>
                </form>

                {message && <p className="status-message">{message}</p>}

                <p className="footer-text">
                    Already have an account? <a href="#" onClick={(e) => { e.preventDefault(); navigate('/login'); }}>Sign In</a>
                </p>
            </div>
        </div>
    );
};

export default Register;

.evaluation-page {
  min-height: 100vh;
  background:
    radial-gradient(circle at top left, rgba(59, 130, 246, 0.14), transparent 28%),
    linear-gradient(180deg, #071022 0%, #0e1930 55%, #12253e 100%);
  color: #f8fafc;
}

.evaluation-content {
  max-width: 1420px;
  margin: 0 auto;
  padding: 2rem;
}

.evaluation-hero {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  gap: 1rem;
  margin-bottom: 1.2rem;
}

.evaluation-hero h1 {
  margin: 0;
  font-size: 2.3rem;
}

.evaluation-hero p {
  margin: 0.4rem 0 0;
  color: #94a3b8;
}

.evaluation-hero__actions {
  display: flex;
  gap: 0.7rem;
}

.evaluation-primary-btn,
.evaluation-secondary-btn {
  border-radius: 0.75rem;
  padding: 0.65rem 1rem;
  font-weight: 700;
  border: 1px solid transparent;
  cursor: pointer;
}

.evaluation-primary-btn {
  background: rgba(6, 95, 70, 0.9);
  border-color: rgba(16, 185, 129, 0.35);
  color: #d1fae5;
}

.evaluation-secondary-btn {
  background: rgba(30, 41, 59, 0.75);
  border-color: rgba(148, 163, 184, 0.3);
  color: #e2e8f0;
}

.evaluation-primary-btn:disabled {
  opacity: 0.65;
  cursor: not-allowed;
}

.evaluation-score-card {
  display: flex;
  justify-content: space-between;
  gap: 1rem;
  margin-bottom: 1rem;
  border-radius: 1rem;
  border: 1px solid rgba(148, 163, 184, 0.2);
  background: rgba(13, 23, 42, 0.86);
  padding: 1rem 1.2rem;
}

.evaluation-score-main {
  display: flex;
  flex-direction: column;
  gap: 0.35rem;
}

.evaluation-score-main strong {
  font-size: 2.5rem;
  line-height: 1;
}

.evaluation-status {
  width: fit-content;
  padding: 0.25rem 0.75rem;
  border-radius: 999px;
  font-size: 0.75rem;
  font-weight: 700;
}

.evaluation-status.is-live {
  color: #fca5a5;
  border: 1px solid rgba(248, 113, 113, 0.35);
  background: rgba(127, 29, 29, 0.25);
}

.evaluation-status.is-completed {
  color: #86efac;
  border: 1px solid rgba(16, 185, 129, 0.35);
  background: rgba(6, 78, 59, 0.28);
}

.evaluation-score-side {
  display: flex;
  flex-direction: column;
  align-items: flex-end;
  justify-content: center;
  gap: 0.2rem;
  color: #94a3b8;
}

.evaluation-score-side strong {
  color: #facc15;
  font-size: 2rem;
}

.evaluation-arena {
  position: relative;
  display: grid;
